	cv.width = img_lg.width;
	cv.height = img_lg.height;
	const ctx = cv.getContext("2d");
	ctx.drawImage(img_lg, 0, 0);
	const cv_sm = document.createElement("canvas");
	cv_sm.width = img_sm.width;
	cv_sm.height = img_sm.height;
